const item = items[0]?.json ?? {};

// Use ISO date for stable, auditable reports
const dateStr = new Date().toISOString().slice(0, 10);

const prompt = `
You are an operations consultant producing a clear, concise **weekly business status report** for leadership.

Write a Markdown report using the following structure and data. Be concise but readable. Use bullet points where appropriate.

# Weekly Business Status Report - ${dateStr}

## 1. Highlights
Use "highlights" to summarise key wins and notable updates.

## 2. Sales & Pipeline
Use "sales_pipeline" to describe new leads, pipeline movement, and closed deals.

## 3. Marketing & Growth
Use "marketing" to summarise campaigns, channel performance, and experiments.

## 4. Operations & Delivery
Use "operations" to cover project delivery, operational issues, and process improvements.

## 5. Product / Technology
Use "product_tech" to summarise shipped features, bugs fixed, and tech debt work.

## 6. Finance & Admin
Use "finance_admin" to highlight important expenses, invoicing, and cashflow-related notes.

## 7. Risks & Issues
Use "risks" to describe current risks and mitigations.

## 8. Priorities for Next Week
Use "next_week" to list the top 3-5 priorities and any dependencies.

Here is the raw data (JSON):

${JSON.stringify(item, null, 2)}

Return **only** the final Markdown report, no commentary.
`.trim();

return [
  {
    json: {
      date: dateStr,
      prompt,
    },
  },
];

const source = items[0]?.json ?? {};

function firstString(...values) {
  for (const value of values) {
    if (typeof value === 'string' && value.trim()) {
      return value.trim();
    }
  }
  return '';
}

// Common local/OpenAI-compatible/llama.cpp/Ollama-ish response shapes.
let content = firstString(
  source.response,
  source.report,
  source.content,
  source.text,
  source.output,
  source.generated_text,
  source.message?.content,
  source.choices?.[0]?.message?.content,
  source.choices?.[0]?.text,
  source.results?.[0]?.text,
  source.data?.response,
  source.data?.report,
  source.data?.content,
  source.data?.text,
  source.data?.output,
  source.data?.message?.content,
  source.data?.choices?.[0]?.message?.content,
  source.data?.choices?.[0]?.text
);

// Some wrappers return an array of generated parts.
if (!content && Array.isArray(source.output)) {
  content = source.output
    .map(part => typeof part === 'string' ? part : part?.content || part?.text || '')
    .filter(Boolean)
    .join('\n')
    .trim();
}

if (!content) {
  const availableKeys = Object.keys(source).sort().join(', ');
  throw new Error(`LLM response did not contain an expected report field. Available top-level fields: ${availableKeys}`);
}

return [{
  json: {
    ...source,
    report: content,
  },
}];

const source = items[0]?.json ?? {};
const report = source.report;

if (typeof report !== 'string' || !report.trim()) {
  throw new Error('Preview / Save Report expected a non-empty report field');
}

const generatedAt = new Date().toISOString();

return [
  {
    json: {
      ...source,
      report,
      preview_markdown: report,
      generated_at: generatedAt,
      delivery_status: 'ready_for_email',
    },
  },
];

const source = items[0]?.json ?? {};

const required = [
  'highlights',
  'sales_pipeline',
  'marketing',
  'operations',
  'product_tech',
  'finance_admin',
  'risks',
  'next_week',
];

const missing = [];
const tooShort = [];

for (const field of required) {
  const value = source[field];
  if (typeof value !== 'string' || !value.trim()) {
    missing.push(field);
    continue;
  }
  if (value.trim().length < 8) {
    tooShort.push(field);
  }
}

if (missing.length || tooShort.length) {
  throw new Error([
    missing.length ? `Missing required inputs: ${missing.join(', ')}` : '',
    tooShort.length ? `Inputs too short to produce a useful report: ${tooShort.join(', ')}` : '',
  ].filter(Boolean).join('; '));
}

const totalInputLength = required
  .map(field => source[field].trim().length)
  .reduce((sum, length) => sum + length, 0);

if (totalInputLength < 120) {
  throw new Error('Input quality guardrail failed: not enough business context to generate a useful weekly report');
}

return [{
  json: {
    ...source,
    input_quality: {
      status: 'passed',
      checked_fields: required,
      total_input_length: totalInputLength,
    },
  },
}];

const source = items[0]?.json ?? {};

if (typeof source.report !== 'string' || !source.report.trim()) {
  throw new Error('Audit log expected a non-empty report field');
}

const auditRecord = {
  audit_id: `weekly-status-${source.date || new Date().toISOString().slice(0, 10)}-${Date.now()}`,
  generated_at: source.generated_at || new Date().toISOString(),
  report_date: source.date,
  delivery_status: source.delivery_status || 'ready_for_email',
  source_data: {
    highlights: source.highlights,
    sales_pipeline: source.sales_pipeline,
    marketing: source.marketing,
    operations: source.operations,
    product_tech: source.product_tech,
    finance_admin: source.finance_admin,
    risks: source.risks,
    next_week: source.next_week,
  },
  report_markdown: source.report,
};

return [{
  json: {
    ...source,
    audit_record: auditRecord,
    audit_status: 'captured_in_workflow_output',
  },
}];

const source = items[0]?.json ?? {};

// Demo placeholder: pass through by default so the workflow remains runnable.
// For senior leadership or external recipients, replace this node with a Wait/Form/approval workflow.
const approvalRequired = source.approval_required ?? false;
const approved = source.approved ?? true;

if (approvalRequired && !approved) {
  throw new Error('Human approval required before email delivery');
}

return [{
  json: {
    ...source,
    approval: {
      required: approvalRequired,
      approved,
      mode: 'demo_auto_approved_placeholder',
    },
  },
}];

const source = items[0]?.json ?? {};
const error = source.error ?? source;

const message = error.message || error.description || source.message || 'Unknown LLM workflow failure';
const failedAt = new Date().toISOString();

const alertMarkdown = [
  '# Weekly Status Report Workflow Failure',
  '',
  `Time: ${failedAt}`,
  `Node / stage: ${source.node?.name || source.node || source.stage || 'LLM response path'}`,
  `Error: ${message}`,
  '',
  'Recommended action:',
  '- Check whether the local LLM endpoint is running and reachable.',
  '- Check the HTTP response shape returned by the model endpoint.',
  '- Review the input guardrail output and source business notes.',
].join('\n');

return [{
  json: {
    alert_type: 'weekly_status_report_failure',
    failed_at: failedAt,
    alert_subject: 'Weekly status report workflow failed',
    alert_markdown: alertMarkdown,
    original_payload: source,
  },
}];

const source = items[0]?.json ?? {};

return [{
  json: {
    ...source,
    alert_delivery_status: 'prepared_demo_payload_replace_with_slack_email_or_incident_node',
  },
}];
